import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const x=JSON.parse('{"title":"物语系列强化","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/物语系列强化.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/物语系列强化.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/物语系列强化.md"};function d(o,r,_,l,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"物语系列强化",tabindex:"-1"},[t("物语系列强化 "),p("a",{class:"header-anchor",href:"#物语系列强化","aria-label":'Permalink to "物语系列强化"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004D")])])],-1),n('<h1 id="物语系列强化-1" tabindex="-1">物语系列强化 <a class="header-anchor" href="#物语系列强化-1" aria-label="Permalink to &quot;物语系列强化&quot;">​</a></h1><p>物语系列强化<br> 特异本质</p><p>你与怪异的相遇，从这个夏天开始。</p><p>特别说明：本系列技艺虽然归属技艺分类，但实际上是你与名为【怪异】的神/怪物/现象相遇后，通过某种手段获得了怪异身上的某些能力，故个别技艺的强化除原本价格外还需支付额外的XP，这视为你为了从怪异身上获取能力消耗了额外的经验值提升与怪异间的好感度，所需XP在每项技艺中均有额外标注。<br> 每项物语系列的同名技艺必须逐级购买，可以购买多个不同名的技艺。</p><p>【历与吸血鬼】<br> D+500<br> 一切的一切都要从那天，你在地铁中多看了那只吸血鬼一眼开始说起。。</p><p>你获得了1点快速医疗点数（医疗点12）。<br> 你获得了【防弹】特性，基于天生防御。<br> 【当吸血鬼遭遇蛇】：当你受到毒素异常点数时，毒素异常点数的负面效果翻倍计算。因此特性额外丢失的生命值会在移除所有毒素异常点数时一并恢复。</p><p>C+1000<br> 命运跟你开了个玩笑，你坦然受之。即便被她的眷属大卸八块，你也能慢慢挣扎着爬起来，对她痛苦地微笑。</p><p>你额外获得了1点快速医疗点数（医疗点12）。<br> 你现在无需休息，无需进食。<br> 你获得了【坚韧】特性，同样基于天生防御。</p><p>B+2000</p><p>你说着你只是个普通人，你告诉她你不想成为吸血鬼，可转眼，你便为她杀了最强的吸血鬼猎人。<br> 你额外获得了4点快速医疗点数（医疗点48）。<br> 你的四肢（包括头部）获得了可以立即再生的能力，通常而言，这是一个自由动作。</p><p>A+4000</p><p>现在你终于意识到，你已经不仅仅是一个吸血鬼的眷属了，你成为了与吸血鬼共生的怪异。<br> 你也终于接受，这个世上能陪你到最后的只有她——吸血鬼。</p><p>每影片一次，你可以在你受到致死伤害后将你的意志储存在你的四肢/躯干/头部。这部分被保留下的肢体只剩观察/感知/移动（如果这部分肢体可以移动的话）/言语（如果这部分肢体可以说话的话，但不能使用凭借言语施法的能力）的能力。<br> 这部分肢体具有跟你的意志池上限相同的结构值，若一周后该肢体没有被摧毁，则你可以复活，这是一个A级诅咒来源的复活效果。<br> 选择一个物理伤害类型：穿刺/挥砍/钝击，你现在能将受到的该类型伤害降低至一半。</p><p>————————————————————</p><p>【黑仪与蟹】<br> B+2000+12xp<br> 你遇到了一只螃蟹，这似乎与你爱吃的螃蟹不同。<br> 于是你把你遭受的恶意交给了它，作为交换，它夺走了你的体重。</p><p>每影片一次，当你受到致死伤害时，你可以将这次伤害以及附带的所有负面效果转移给重蟹，若如此做，则你会如同没受到这次攻击影响一般继续战斗，这是一个A级附身来源的无敌效果。然而这并不代表你治好了转移走的伤害，战斗结束后，你必须消耗一个整轮动作将伤害转回自己身上。若你不如此做，每经过一小时，你便受到1点不可避免的耐力属性伤害，最低使你的耐力降至1点。<br> 你不能将任何消耗品/吸血/快速医疗/医疗点数相关的能力直接用于治疗重蟹。</p><p>——————————————————<br> 【骏河与猴】<br> D+500<br> 那个夏天，你打开了一个盒子。<br> 你看到了一只毛茸茸的断手，看上去好像来自猩猩。<br> 你听过它的传说，于是你开始许愿。</p><p>你的天生武器伤害增加3L。<br> 你的强韧豁免提升2点增强加值，你的反射豁免提升2点增强加值。</p><p>C+1000</p><p>现在你知道了，这不是什么毛绒玩具，更不是猩猩的手。<br> 这是恶魔之手，你的许愿其实是在于恶魔做交易。<br> 你变得小心翼翼，不敢与他人深入接触以防别人成为恶魔交易牺牲的目标。<br> 然而，你的愿望还在持续生效。</p><p>你的天生武器伤害再加3L。<br> 你的运动检定获得3dp的增强加值。<br> 你的武技检定获得3dp的增强加值。</p><p>额外支付20xp，你获得特殊能力：【雨披恶魔】。</p><p>即便如此，你的内心深处还是向恶魔之手许下了新的愿望。</p><p>消耗一个移动动作，你披上了雨衣，手臂变得粗壮并长出鬃毛，进入名为【雨披恶魔】的状态，持续一个场景。<br> 【雨披恶魔】：你从【骏河与猴】中获得的所有好处翻倍。你的触及范围提升5米。</p><p>—————————————————<br> 【抚子与蛇】<br> D+500+2xp<br> 与他人不同，你和怪异的相遇是完全被动的。<br> 你被诅咒了。<br> 即便你明确地拒绝了那个人，却还是要承受喜欢他的人对你的嫉妒和诅咒。<br> 名为【蛇切绳】的怪异缠上了你。</p><p>习得本技艺后，拥有灵感视觉的生物看到你时会看到你的身体被两条白蛇缠绕，时刻紧紧地勒住你。<br> 购买本能力组后，你的攻击命中后会附带1点不可豁免的毒素点数（诅咒来源）。此后【抚子与蛇】每提升一个支线等级，所附带的不可豁免的毒素点素就提升1点。</p><p>C+1000+4xp</p><p>当你知道你被诅咒之后，你想做的仅仅是拔除诅咒。他来帮你拔除诅咒，一切都很顺利，但你看到了他的她。<br> 所以，你吞下了“蛇之符”成为了蛇神。</p><p>你的触觉感知方式现在可以在敏感范围内模糊定位，并具有C级特异本质的侦测等级。</p><p>B+2000+8xp<br> 单相思是幸福的，为了维持这种幸福感，你决定把他杀了。<br> 杀了他，你才能拥有永远的单相思。<br> 他是吸血鬼，他的弱点便是毒。<br> 真是巧合，你是蛇神，最毒的蛇神。</p><p>你的触觉感知方式可以在敏感范围内精确定位。<br> 当你攻击命中后，你对受到你所施加毒素异常点数的单位具有【真实视觉】，持续一个场景。<br> 你的敏感范围增加一倍。</p><p>A+4000+16xp</p><p>你已经说不清楚你到底是想拥有他还是拥有喜欢他的感觉。你的头发变成了白蛇，感觉很糟，你并不是美杜莎，也不想成为她。<br> 现在你不仅想杀了他，还想杀了她和她，所有跟他有关的幸福都只能留下一个，便是你的单相思。</p><p>现在你的攻击会附带等同伤害值的毒素异常点数（诅咒来源），强韧豁免。<br> 每轮一次，你可以令一个单位身上由你施加的毒素异常点数立即产生一次负面效果。</p><p>【如果你不听蛇的话…】：你现在可以控制由你施加的毒素异常点数是否产生负面效果，这需要具有毒素异常点数的单位至少被你模糊定位。<br> 若一个单位受到你施加的毒素异常点数超过了其耐力/决心中较高者时，你可以使毒素异常点数停止生效并对其发布3条指令，然后你决定其在遵从或违背指令时毒素异常点数会继续生效。</p><p>【真宵与蜗牛】<br> B+2000<br> 遇到蜗牛的时候，你其实只是在一个想回家与不想回家的选择中徘徊。但是既然遇到了蜗牛，那你就失去了回家的可能。<br> 这并非是你忘记了路，而是本质性的记忆信息无法在你的脑中遗留。</p><p>你免疫精神束缚点数带来的减值及严重状态。<br> 你免疫恐惧点数带来的减值及严重状态。<br> 你免疫魅惑点数带来的减值及严重状态。<br> 你免疫沮丧点数带来的减值及严重状态。</p><p>作为代价，如果让强化了本技艺的轮回者带路/独自行动，那么便一定会迷路，仿佛陷入了莫比乌斯环一般在原地打转，除非换其他人来给他带路。这是一个S级命运类来源的混乱效果。</p><p>【火怜与蜂】<br> D+500<br> 围猎火蜂与其说是诅咒，不如说是一种毒。你只是想教训一下散播这种“诅咒”的源头，却不想自己成为了对方的目标。</p><p>战斗回合开始时，你受到一点不可豁免的燃烧点数（诅咒来源）。当你身上具有燃烧异常点数时，你的每一次近战攻击命中后都会附带1点不可豁免的燃烧点数（诅咒来源）。</p><p>【翼与猫】<br> D+500+2xp<br> 你被一只猫给诱惑了。<br> 其实你自己也说不清楚，到底是名为【障猫】的怪异找到了你，还是你找到了它。<br> 总之在这种暧昧的前提下，【障猫】盯上了你。</p><p>【不被知晓的…】：每轮一次，当你攻击检定成功数低于期望值的1/3时，由St重新投掷这一攻击检定，重新投掷的攻击会造成火焰伤害。</p><p>【翼与虎】<br> 前置：翼与猫<br> C+1000+4xp</p><p>这不是怪异，确切来说不是你遇到的怪异，而是你产生的怪异。<br> 一只老虎？或者一团火焰？<br> 它不知道你是谁，你也不知道它的存在，但是它诞生的目的只有一个——烧掉你所恨的一切。</p><p>当【不被知晓的…】特性生效时，造成的伤害类型在原伤害类型与火焰伤害中取优计算。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',47)])])}const f=b(s,[["render",d]]);export{x as __pageData,f as default};
